import { roles } from '../data';

const navItems = [
  { group: 'Overview' },
  { id: 'dashboard', icon: '🏠', label: 'Dashboard' },
  { group: 'Alumni Network' },
  { id: 'search', icon: '🔍', label: 'Search Alumni' },
  { id: 'map', icon: '🗺️', label: 'World Map' },
  { group: 'Connect' },
  { id: 'mentorship', icon: '🤝', label: 'Mentorship', badge: 3 },
  { id: 'events', icon: '📅', label: 'Events' },
  { id: 'jobs', icon: '💼', label: 'Jobs & Internships' },
  { group: 'Community' },
  { id: 'blogs', icon: '✍️', label: 'Alumni Blogs' },
  { id: 'stories', icon: '⭐', label: 'Success Stories' },
  { id: 'gallery', icon: '🖼️', label: 'Event Gallery' },
  { id: 'fundraising', icon: '❤️', label: 'Fundraising' },
  { id: 'ai', icon: '🤖', label: 'AI Recommender' },
  { id: 'admin', icon: '🛡️', label: 'Admin Panel', adminOnly: true },
];

export default function Sidebar({ currentPage, onNavigate, user, role, mentorSeen, onEditProfile }) {
  return (
    <nav className="sidebar">
      {/* Logo */}
      <div className="logo">
        <img src="data:image/png;base64," alt="AlumniConnect Logo" style={{width:44,height:44,objectFit:'contain',borderRadius:6}} />
        <h1>AlumniConnect</h1>
        <small>Smart Alumni Platform</small>
      </div>

      {/* Navigation */}
      {navItems.map((item, i) => {
        if (item.group) return <div key={i} className="ng">{item.group}</div>;
        if (item.adminOnly && role !== 'Admin') return null;
        const showBadge = item.badge && item.id === 'mentorship' && !mentorSeen;
        return (
          <div
            key={item.id}
            className={`ni ${currentPage === item.id ? 'active' : ''}`}
            onClick={() => onNavigate(item.id)}
          >
            <span className="ic">{item.icon}</span>
            <span>{item.label}</span>
            {showBadge && <span className="nbadge">{item.badge}</span>}
          </div>
        );
      })}

      {/* User Footer */}
      <div className="sf">
        <div className="sfav">{user?.name ? user.name[0].toUpperCase() : 'U'}</div>
        <div className="sfinfo">
          <p>{user?.name || 'User'}</p>
          <small>{user?.role || 'Guest'}</small>
        </div>
        <button className="sfedit" onClick={onEditProfile}>✎</button>
      </div>
    </nav>
  );
}